import{_ as a,c as o,o as i,a1 as t}from"./chunks/framework.DDNAyvCW.js";const p=JSON.parse('{"title":"Mobile FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/faq/index.md","filePath":"docs/mobile/faq/index.md"}'),n={name:"docs/mobile/faq/index.md"};function r(s,e,l,c,h,d){return i(),o("div",null,e[0]||(e[0]=[t('<h1 id="mobile-faq" tabindex="-1">Mobile FAQ <a class="header-anchor" href="#mobile-faq" aria-label="Permalink to &quot;Mobile FAQ&quot;">​</a></h1><h2 id="server-connection-failed" tabindex="-1">Server Connection Failed? <a class="header-anchor" href="#server-connection-failed" aria-label="Permalink to &quot;Server Connection Failed?&quot;">​</a></h2><ul><li>Check whether your network connection is working normally</li><li>Disable network proxy tools if they interfere with SSH connections</li></ul><h2 id="connection-drops-when-the-app-goes-to-the-background" tabindex="-1">Connection Drops When the App Goes to the Background? <a class="header-anchor" href="#connection-drops-when-the-app-goes-to-the-background" aria-label="Permalink to &quot;Connection Drops When the App Goes to the Background?&quot;">​</a></h2><ul><li>On Android, set the app battery policy to <code>Unrestricted</code> to reduce background disconnects</li></ul><h2 id="why-did-my-asset-data-disappear" tabindex="-1">Why Did My Asset Data Disappear? <a class="header-anchor" href="#why-did-my-asset-data-disappear" aria-label="Permalink to &quot;Why Did My Asset Data Disappear?&quot;">​</a></h2><p>This usually happens for one of these reasons:</p><ul><li>Data isolation: different accounts use different datasets, so logging out or switching accounts can show a different asset list</li><li>App removal: uninstalling the app also removes local data</li></ul><h2 id="how-do-i-report-an-issue" tabindex="-1">How Do I Report an Issue? <a class="header-anchor" href="#how-do-i-report-an-issue" aria-label="Permalink to &quot;How Do I Report an Issue?&quot;">​</a></h2><p>You can contact Chaterm through:</p><ul><li>In-app feedback: <code>Profile → Usage &amp; Feedback → Issue Feedback</code></li><li>Email support: <code>support@chaterm.ai</code></li></ul><h2 id="which-ai-models-are-supported-how-do-i-switch" tabindex="-1">Which AI Models Are Supported? How Do I Switch? <a class="header-anchor" href="#which-ai-models-are-supported-how-do-i-switch" aria-label="Permalink to &quot;Which AI Models Are Supported? How Do I Switch?&quot;">​</a></h2><p>After signing in, go to <a href="/docs/mobile/profile/#model-selection">Profile &gt; AI Settings &gt; Model Selection</a> to view and switch models. Supported models include flagship models from OpenAI, Gemini, and other major providers. Available models vary by subscription tier — check the app for the current list.</p><h2 id="data-sync-not-working" tabindex="-1">Data Sync Not Working? <a class="header-anchor" href="#data-sync-not-working" aria-label="Permalink to &quot;Data Sync Not Working?&quot;">​</a></h2><ul><li>Confirm you are signed in (sync is unavailable without an account)</li><li>Check whether your network connection is working</li><li>Go to <a href="/docs/mobile/profile/#data-management">Profile &gt; Data Management</a> and confirm the sync toggle is on</li><li>If the issue persists, try signing out and back in, then sync again</li></ul><h2 id="what-can-i-use-without-signing-in" tabindex="-1">What Can I Use Without Signing In? <a class="header-anchor" href="#what-can-i-use-without-signing-in" aria-label="Permalink to &quot;What Can I Use Without Signing In?&quot;">​</a></h2><p>Without signing in you can add and manage local assets and open SSH connections. AI Chat and cloud data sync require a signed-in account.</p><h2 id="troubleshooting-checklist" tabindex="-1">Troubleshooting Checklist <a class="header-anchor" href="#troubleshooting-checklist" aria-label="Permalink to &quot;Troubleshooting Checklist&quot;">​</a></h2><p>If the problem is related to connection or sign-in, confirm these first:</p><ul><li>The app version is the latest release</li><li>Your current network can reach the target host</li><li>Your account is still signed in</li><li>The model and AI settings are configured correctly</li></ul>',20)]))}const g=a(n,[["render",r]]);export{p as __pageData,g as default};
